const XLSX = require('xlsx');
const workbook = XLSX.readFile(config.filePath);
const sheetName = config.sheetName && workbook.SheetNames.includes(config.sheetName)
  ? config.sheetName
  : workbook.SheetNames[0];
const rows = XLSX.utils.sheet_to_json(
  workbook.Sheets[sheetName],
  { header: config.hasHeader ? undefined : 1 }
);
return { rows, sheetName, totalRows: rows.length, availableSheets: workbook.SheetNames };
